import * as React from "react";
import {
  makeStyles,
  tokens,
  shorthands,
  mergeClasses,
  Text,
} from "@fluentui/react-components";
import type { DayScore, TimelineData } from "../types";
import { scoreBand } from "../utils/timeline";

export interface WeekViewDay {
  score: DayScore;
  timeline: TimelineData | null;
}

export type WeekViewData = (WeekViewDay | null)[];

interface WeekDashboardProps {
  week: WeekViewData;
}

const useStyles = makeStyles({
  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(5, minmax(0, 1fr))",
    columnGap: "16px",
    ...shorthands.padding("24px"),
  },
  col: {
    backgroundColor: tokens.colorNeutralBackground1,
    ...shorthands.borderRadius("8px"),
    ...shorthands.padding("16px"),
    ...shorthands.border("1px", "solid", tokens.colorNeutralStroke2),
    display: "flex",
    flexDirection: "column",
    rowGap: "12px",
    minHeight: "200px",
  },
  emptyCol: {
    opacity: 0.5,
  },
  weekday: {
    fontSize: tokens.fontSizeBase200,
    textTransform: "uppercase",
    letterSpacing: "0.5px",
    color: tokens.colorNeutralForeground3,
  },
  dayNum: {
    fontSize: tokens.fontSizeHero700,
    fontWeight: tokens.fontWeightSemibold,
    lineHeight: 1,
  },
  scorePct: {
    fontSize: tokens.fontSizeHero900,
    fontWeight: tokens.fontWeightSemibold,
    lineHeight: 1,
  },
  scoreGood: { color: tokens.colorStatusSuccessForeground1 },
  scoreWarn: { color: tokens.colorStatusWarningForeground1 },
  scoreBad: { color: tokens.colorStatusDangerForeground1 },
  scoreFuture: { color: tokens.colorNeutralForegroundDisabled },
  scoreLabel: {
    fontSize: tokens.fontSizeBase200,
    color: tokens.colorNeutralForeground2,
    lineHeight: "18px",
  },
  bar: {
    height: "6px",
    backgroundColor: tokens.colorNeutralBackground5,
    ...shorthands.borderRadius("3px"),
    ...shorthands.overflow("hidden"),
  },
  barFill: {
    height: "100%",
    ...shorthands.borderRadius("3px"),
  },
  fillGood: { backgroundColor: tokens.colorStatusSuccessForeground1 },
  fillWarn: { backgroundColor: tokens.colorStatusWarningForeground1 },
  fillBad: { backgroundColor: tokens.colorStatusDangerForeground1 },
  factorCount: {
    marginTop: "auto",
    fontSize: tokens.fontSizeBase200,
    color: tokens.colorNeutralForeground3,
  },
});

/**
 * Layout 5 colonnes (Lun → Ven) pour la vue semaine du dashboard Gr33t.
 * Chaque colonne affiche le score % du jour avec une barre de progression.
 * Les jours manquants (null) sont rendus en grisé.
 */
const WeekDashboard: React.FC<WeekDashboardProps> = ({ week }) => {
  const styles = useStyles();
  const weekdays = ["Lundi", "Mardi", "Mercredi", "Jeudi", "Vendredi"];

  return (
    <div className={styles.grid}>
      {weekdays.map((label, i) => {
        const day = week[i];
        if (!day) {
          return (
            <div key={i} className={mergeClasses(styles.col, styles.emptyCol)}>
              <div className={styles.weekday}>{label}</div>
              <Text>—</Text>
            </div>
          );
        }
        const band = scoreBand(day.score.score);
        const scoreColorClass = {
          good: styles.scoreGood,
          warn: styles.scoreWarn,
          bad: styles.scoreBad,
          future: styles.scoreFuture,
        }[band];
        const fillColorClass = {
          good: styles.fillGood,
          warn: styles.fillWarn,
          bad: styles.fillBad,
          future: "",
        }[band];
        const isFuture = day.score.score === null;
        return (
          <div key={i} className={styles.col}>
            <div>
              <div className={styles.weekday}>{label}</div>
              <div className={styles.dayNum}>{day.score.dayNum}</div>
            </div>
            <div className={mergeClasses(styles.scorePct, scoreColorClass)}>
              {isFuture ? "—" : `${day.score.score}%`}
            </div>
            <div className={styles.scoreLabel}>
              {isFuture ? "À venir" : day.score.scoreLabel}
            </div>
            <div className={styles.bar}>
              {!isFuture && day.score.score !== null && (
                <div
                  className={mergeClasses(styles.barFill, fillColorClass)}
                  style={{ width: `${day.score.score}%` }}
                />
              )}
            </div>
            {day.score.factors && (
              <div className={styles.factorCount}>
                {day.score.factors.length} facteurs · {day.timeline?.events.length ?? 0} événements
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
};

export default WeekDashboard;
