import * as React from "react";
import { useCallback, useEffect, useState } from "react";
import {
  makeStyles,
  tokens,
  shorthands,
  Button,
  Text,
  Spinner,
} from "@fluentui/react-components";
import { ChevronLeft20Regular, ChevronRight20Regular } from "@fluentui/react-icons";
import WeekDashboard from "../components/WeekDashboard";
import type { WeekViewData } from "../components/WeekDashboard";
import { useTeamsToken, clearTeamsToken } from "./useTeamsToken";
import { fetchWeekRecovery } from "../calendar/calendarReader";
import { recoveryToDayScore } from "../adapters/recoveryToDayScore";

const useStyles = makeStyles({
  root: {
    minHeight: "100vh",
    backgroundColor: tokens.colorNeutralBackground2,
    display: "flex",
    flexDirection: "column",
  },
  header: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    ...shorthands.padding("16px", "24px"),
    backgroundColor: tokens.colorNeutralBackground1,
    borderBottomWidth: "1px",
    borderBottomStyle: "solid",
    borderBottomColor: tokens.colorNeutralStroke2,
  },
  title: {
    fontSize: tokens.fontSizeBase500,
    fontWeight: tokens.fontWeightSemibold,
  },
  nav: { display: "flex", alignItems: "center", columnGap: "8px" },
  center: {
    flex: 1,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    ...shorthands.padding("48px"),
  },
  error: {
    color: tokens.colorStatusDangerForeground1,
    fontFamily: tokens.fontFamilyMonospace,
    fontSize: tokens.fontSizeBase200,
    maxWidth: "500px",
    textAlign: "center",
  },
});

function formatWeekLabel(monday: Date): string {
  const friday = new Date(monday);
  friday.setDate(monday.getDate() + 4);
  const fmt = (d: Date) =>
    d.toLocaleDateString("fr-FR", { day: "numeric", month: "long" });
  return `Semaine du ${fmt(monday)} au ${fmt(friday)}`;
}

/** Retourne le lundi de la semaine contenant `d` (00:00 local). */
function getMondayOf(d: Date): Date {
  const day = d.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  const monday = new Date(d);
  monday.setDate(d.getDate() + diff);
  monday.setHours(0, 0, 0, 0);
  return monday;
}

function toIsoDate(d: Date): string {
  const pad = (n: number) => n.toString().padStart(2, "0");
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}

const DashboardApp: React.FC = () => {
  const styles = useStyles();
  const [monday, setMonday] = useState<Date>(() => getMondayOf(new Date()));
  const [dataStatus, setDataStatus] = useState<
    "idle" | "loading" | "ready" | "empty" | "error"
  >("idle");
  const [dataError, setDataError] = useState<string | null>(null);
  const [week, setWeek] = useState<WeekViewData | null>(null);

  const {
    status: authStatus,
    token,
    error: authError,
    signIn,
    retry: retryAuth,
  } = useTeamsToken();

  const loadWeek = useCallback(
    async (mondayDate: Date, accessToken: string) => {
      setDataStatus("loading");
      setDataError(null);
      try {
        const mondayStr = toIsoDate(mondayDate);
        const recoveries = await fetchWeekRecovery(accessToken, mondayStr);
        const adapted: WeekViewData = recoveries.map((r) => {
          if (!r) return null;
          const { score, timeline } = recoveryToDayScore(r);
          return { score, timeline };
        });
        setWeek(adapted);
        setDataStatus(adapted.every((d) => d === null) ? "empty" : "ready");
      } catch (err) {
        const message = (err as Error).message;
        if (message.includes("401") || message.includes("Unauthorized")) {
          clearTeamsToken();
        }
        setDataError(message);
        setDataStatus("error");
      }
    },
    []
  );

  useEffect(() => {
    if (authStatus === "ready" && token) {
      void loadWeek(monday, token);
    }
  }, [authStatus, token, monday, loadWeek]);

  const shiftWeek = (days: number) => {
    const next = new Date(monday);
    next.setDate(monday.getDate() + days);
    setMonday(next);
  };

  // Statut global prioritisé : auth en 1er, puis data
  const status =
    authStatus === "idle" || authStatus === "loading"
      ? "loading"
      : authStatus === "authRequired"
      ? "authRequired"
      : authStatus === "error"
      ? "error"
      : dataStatus === "loading" || dataStatus === "idle"
      ? "loading"
      : dataStatus === "empty"
      ? "empty"
      : dataStatus === "error"
      ? "error"
      : "ready";
  const error =
    authStatus === "error" ? authError : dataStatus === "error" ? dataError : null;

  return (
    <div className={styles.root}>
      <div className={styles.header}>
        <Text className={styles.title}>{formatWeekLabel(monday)}</Text>
        <div className={styles.nav}>
          <Button
            icon={<ChevronLeft20Regular />}
            appearance="subtle"
            onClick={() => shiftWeek(-7)}
            aria-label="Semaine précédente"
          />
          <Button
            appearance="secondary"
            onClick={() => setMonday(getMondayOf(new Date()))}
          >
            Aujourd'hui
          </Button>
          <Button
            icon={<ChevronRight20Regular />}
            appearance="subtle"
            onClick={() => shiftWeek(7)}
            aria-label="Semaine suivante"
          />
        </div>
      </div>

      {status === "loading" && (
        <div className={styles.center}>
          <Spinner size="large" label="Chargement…" />
        </div>
      )}

      {status === "authRequired" && (
        <div className={styles.center}>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "16px", textAlign: "center" }}>
            <Text>Connecte-toi pour afficher tes données Gr33t.</Text>
            <Button appearance="primary" onClick={() => void signIn()}>
              Se connecter à Outlook
            </Button>
          </div>
        </div>
      )}

      {status === "empty" && (
        <div className={styles.center}>
          <Text>
            Aucune donnée pour la semaine du <code>{toIsoDate(monday)}</code>.
            <br />
            Lance le script <code>demo-calendar.ts</code> pour peupler le calendrier Gr33t Recovery.
          </Text>
        </div>
      )}

      {status === "error" && (
        <div className={styles.center}>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "12px" }}>
            <Text className={styles.error}>{error}</Text>
            <Button appearance="secondary" onClick={retryAuth}>
              Réessayer
            </Button>
          </div>
        </div>
      )}

      {status === "ready" && week && <WeekDashboard week={week} />}
    </div>
  );
};

export default DashboardApp;
